  ('elementary-64311456-moex-00937', 'elementary-64311456', 'elementary-64311456-moex-110-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '社會工作者在協助一個保護個案，會談中父親認為他唸高中的女兒常常夜宿不歸，屢勸不聽，都是她的 男朋友帶壞女兒，使他束手無策感到憤怒，揚言一旦被他逮到一定要給這男朋友打到致殘，且工具都準 備好了。此時社會工作者應依下列那一個倫理守則順序？', '["保護生命原則、最小傷害原則、隱私守密原則", "保護生命原則、隱私守密原則、最小傷害原則", "保護生命原則、自由自主原則、隱私守密原則", "保護生命原則、隱私守密原則、自由自主原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "afc9a1379873", "answer_pdf_sha1": "36be20ddb9c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
